+  const magnitude = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
+  if (magnitude > 0) {
+    for (let i = 0; i < dims; i++) embedding[i] /= magnitude;
+  }
+
+  return Array.from(embedding);
